INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 160, 101, 122601, 1, 1.5, 1, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 0, 1, 0.029, 1, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (111, 120, 102, 122401, 2, 2.5, 3, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 0, 0, 0.014, 2, 105, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 350, 103, 122501, 3, 2.5, 2, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 1, 0, 0.017, 3, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 130, 104, 107501, 4, 1.5, 3, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 0, 0, 0.016, 4, 110, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 160, 105, 107601, 5, 2.5, 1, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 0, 1, 0.014, 5, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 255, 106, 107801, 6, 3.5, 2, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 1, 0, 0.029, 6, 120, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 160, 107, 110601, 7, 3.5, 1, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 0, 1, 0.013, 7, 120, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 350, 108, 110401, 8, 2.5, 2, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 1, 0, 0.014, 8, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (100, 130, 109, 110501, 9, 1.5, 3, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 0, 0, 0.012, 9, 105, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 200, 110, 115701, 10, 2.5, 1, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 0, 1, 0.014, 10, 105, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 350, 111, 113601, 11, 2.5, 2, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 1, 0, 0.071, 11, 105, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 130, 112, 107901, 12, 1.5, 3, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 0, 0, 0.014, 12, 120, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 200, 113, 108001, 13, 1.5, 2, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 0, 1, 0.022, 13, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (108, 160, 114, 110301, 14, 2.5, 1, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 0, 1, 0.031, 14, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 130, 115, 107701, 15, 0.5, 1, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 0, 0, 0.036, 15, 110, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (95, 350, 116, 113101, 16, 3.5, 2, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 1, 0, 0.048, 16, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 130, 117, 113301, 17, 1.5, 3, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 0, 0, 0.043, 17, 105, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (95, 130, 118, 113201, 18, 1.5, 2, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 0, 0, 0.018, 18, 105, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (108, 160, 119, 117001, 19, 2.5, 2, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 0, 1, 0.021, 19, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 255, 120, 113501, 20, 2.5, 1, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 1, 0, 0.036, 20, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 350, 121, 113401, 21, 2.5, 3, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 1, 0, 0.02, 21, 105, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 130, 122, 110101, 22, 2.5, 1, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 0, 0, 0.018, 22, 110, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (111, 160, 123, 110001, 23, 3.5, 3, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 0, 1, 0.03, 23, 105, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (103, 130, 124, 117201, 24, 1.5, 1, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 0, 0, 0.027, 24, 110, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (108, 160, 125, 117301, 25, 3.5, 2, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 0, 1, 0.02, 25, 105, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 350, 126, 117401, 26, 2.5, 3, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 1, 0, 0.04, 26, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 350, 127, 117101, 27, 3.5, 1, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 1, 0, 0.009, 27, 110, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 255, 128, 122901, 28, 3.5, 1, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 1, 0, 0.022, 28, 120, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (105, 130, 129, 122801, 29, 2.5, 3, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 0, 0, 0.028, 29, 110, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (108, 130, 130, 122701, 30, 3.5, 2, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 0, 1, 0.023, 30, 105, 0);
